import React, { useState, useEffect } from 'react';
import './App.css';

interface Deployment {
  customer: string;
  project: string;
  environment: string;
  branch: string;
  commit: string;
  user: string;
  email: string;
  releaseDate: string;
  buildDate: string;
}

interface ApiResponse {
  pageNumber: number;
  pageSize: number;
  total: number;
  results: Deployment[];
}

function App() {
  const [deployments, setDeployments] = useState<Deployment[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  // Funzione per chiamare l'API
  const fetchDeployments = async () => {
    try {
      setLoading(true);

      // Sostituisci con il tuo endpoint API reale
      const response = await fetch('https://api.tuosito.com/deployments');

      if (!response.ok) {
        throw new Error(`Errore HTTP: ${response.status}`);
      }

      const data: ApiResponse = await response.json();
      setDeployments(data.results);
      setError(null);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Errore sconosciuto');
      console.error('Errore nel recupero dati:', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDeployments();
  }, []);

  // Formatta la data per renderla più leggibile
  const formatDate = (dateString: string) => {
    if (dateString === '0001-01-01T00:00:00') return '-';
    const date = new Date(dateString);
    return date.toLocaleDateString('it-IT', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  // Tag colorato per l'ambiente
  const getEnvironmentBadge = (env: string) => {
    const colors: Record<string, string> = {
      PROD: '#dc3545',
      DEV: '#28a745',
      STAGING: '#ffc107'
    };
    return colors[env] || '#6c757d';
  };

  if (loading) {
    return <div className="loading">Caricamento...</div>;
  }

  if (error) {
    return <div className="error">Errore: {error}</div>;
  }

  return (
    <div className="App">
      <header className="App-header">
        <h1>🚀 Deploy Tracker</h1>
        <button onClick={fetchDeployments}>Aggiorna</button>
      </header>

      <main className="App-main">
        <div className="stats">
          <span>Totali: {deployments.length}</span>
        </div>

        <table className="deployment-table">
          <thead>
            <tr>
              <th>Cliente</th>
              <th>Progetto</th>
              <th>Ambiente</th>
              <th>Branch</th>
              <th>Commit</th>
              <th>Deployer</th>
              <th>Data Release</th>
            </tr>
          </thead>
          <tbody>
            {deployments.map((dep, index) => (
              <tr key={index}>
                <td>{dep.customer}</td>
                <td>{dep.project}</td>
                <td>
                  <span 
                    className="badge"
                    style={{ backgroundColor: getEnvironmentBadge(dep.environment) }}
                  >
                    {dep.environment}
                  </span>
                </td>
                <td>{dep.branch}</td>
                <td className="commit">{dep.commit.substring(0, 7)}</td>
                <td>{dep.user}</td>
                <td>{formatDate(dep.releaseDate)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </main>
    </div>
  );
}

export default App;
